import { Task } from 'wasp/entities';
import { GetTasks } from 'wasp/server/operations';

type GetTasksArgs = {
  overdueOnly?: boolean;
};

export const getTasks: GetTasks<GetTasksArgs, Task[]> = async (args, context) => {
  if (args.overdueOnly) {
    return context.entities.Task.findMany({
      where: {
        dueDate: {
          lt: new Date()
        }
      },
      orderBy: {
        dueDate: 'asc'
      }
    });
  }

  return context.entities.Task.findMany({
    orderBy: {
      dueDate: 'asc'
    }
  });
};

