import React, { useState } from 'react';
import { useQuery } from 'wasp/client/operations';
import { getTasks, createTask } from 'wasp/client/operations';
import './Main.css';

export function MainPage() {
  const [overdueOnly, setOverdueOnly] = useState(false);
  const [description, setDescription] = useState('');
  const [dueDate, setDueDate] = useState('');

  const { data: tasks, isLoading, error } = useQuery(getTasks, { overdueOnly });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !dueDate) return;

    try {
      await createTask({
        description,
        dueDate: new Date(dueDate)
      });
      setDescription('');
      setDueDate('');
    } catch (err: any) {
      window.alert('Error: ' + err.message);
    }
  };

  return (
    <main className="container">
      <h2>Task Deadlines</h2>

      <form onSubmit={handleSubmit} style={{ marginBottom: '20px' }}>
        <div>
          <label>
            Description:
            <input
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
            />
          </label>
        </div>
        <div>
          <label>
            Due Date:
            <input
              type="datetime-local"
              value={dueDate}
              onChange={(e) => setDueDate(e.target.value)}
              required
            />
          </label>
        </div>
        <button type="submit">Add Task</button>
      </form>

      <div style={{ marginBottom: '20px' }}>
        <label>
          <input
            type="checkbox"
            checked={overdueOnly}
            onChange={(e) => setOverdueOnly(e.target.checked)}
          />
          Show Overdue Only
        </label>
      </div>

      {isLoading && <div>Loading...</div>}
      {error && <div>Error: {error.message}</div>}

      {tasks && (
        <ul>
          {tasks.map((task) => (
            <li key={task.id}>
              {task.description} - {new Date(task.dueDate).toLocaleString()}
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

